+/**
+ * SMS notification adapter — delivers notifications via SMS.
+ *
+ * Sends a text message to the recipient phone number. Uses a configurable
+ * transport for SMS delivery; defaults to an in-memory transport for testing.
+ * Inject a real transport (Twilio, AWS SNS, etc.) for production.
+ */
+
+import type { NotificationAdapter } from './notification.adapter.js';
+import type {
+  NotificationPayload,
+  NotificationResult,
+  NotificationType,
+} from '../models/notification.js';
+import { Logger } from '../utils/logger.js';
+
+/**
+ * A formatted SMS message ready for delivery.
+ */
+export interface SmsMessage {
+  to: string;
+  from: string;
+  body: string;
+}
+
+/**
+ * Transport interface for sending SMS messages.
+ * Implement this to integrate with a real SMS provider (Twilio, AWS SNS, etc.).
+ */
+export interface SmsTransport {
+  sendSms(message: SmsMessage): Promise<{ messageId: string }>;
+}
+
+/**
+ * Configuration for the SmsAdapter.
+ */
+export interface SmsAdapterConfig {
+  /** Sender phone number or short code. */
+  fromNumber: string;
+  /** Application name used in message templates. */
+  appName: string;
+  /** Optional custom transport. Defaults to in-memory transport. */
+  transport?: SmsTransport;
+}
+
+const DEFAULT_CONFIG: SmsAdapterConfig = {
+  fromNumber: '+10000000000',
+  appName: 'TaskFlow Pro',
+};
+
+/**
+ * In-memory transport for testing — stores sent messages instead of delivering them.
+ */
+export class InMemorySmsTransport implements SmsTransport {
+  private sent: Array<SmsMessage & { messageId: string }> = [];
+  private nextId = 1;
+
+  async sendSms(message: SmsMessage): Promise<{ messageId: string }> {
+    const messageId = `sms-${String(this.nextId++).padStart(4, '0')}`;
+    this.sent.push({ ...message, messageId });
+    return { messageId };
+  }
+
+  getSentMessages(): Array<SmsMessage & { messageId: string }> {
+    return [...this.sent];
+  }
+
+  clear(): void {
+    this.sent = [];
+    this.nextId = 1;
+  }
+}
+
+/**
+ * SMS message templates keyed by notification type.
+ * Each template receives the notification payload and returns a plain text message body.
+ */
+type SmsTemplateRenderer = (payload: NotificationPayload, appName: string) => string;
+
+const SMS_TEMPLATES: Record<NotificationType, SmsTemplateRenderer> = {
+  'order:confirmation': (payload, appName) =>
+    `[${appName}] Order confirmed! ${payload.body}`,
+
+  'order:status-update': (payload, appName) =>
+    `[${appName}] ${payload.body}`,
+
+  'user:welcome': (payload, appName) =>
+    `Welcome to ${appName}! ${payload.body}`,
+
+  'user:profile-updated': (payload, appName) =>
+    `[${appName}] ${payload.body}`,
+};
+
+/**
+ * Validate that a string looks like a plausible phone number.
+ * Accepts E.164 format: + followed by 7-15 digits.
+ */
+function isValidPhoneNumber(phone: string): boolean {
+  return /^\+[1-9]\d{6,14}$/.test(phone);
+}
+
+export class SmsAdapter implements NotificationAdapter {
+  readonly channel = 'sms' as const;
+  private logger = new Logger('SmsAdapter');
+  private config: SmsAdapterConfig;
+  private transport: SmsTransport;
+  private sentMessages: NotificationPayload[] = [];
+
+  constructor(config?: Partial<SmsAdapterConfig>) {
+    this.config = { ...DEFAULT_CONFIG, ...config };
+    this.transport = this.config.transport ?? new InMemorySmsTransport();
+  }
+
+  /**
+   * Send an SMS notification.
+   *
+   * Validates the recipient phone number, renders the appropriate template,
+   * and delivers through the configured transport.
+   */
+  async send(payload: NotificationPayload): Promise<NotificationResult> {
+    this.logger.info(`Sending SMS to ${payload.recipient}: ${payload.subject}`);
+
+    // Validate recipient
+    const recipient = this.resolveRecipient(payload.recipient);
+    if (!recipient) {
+      const error = `Invalid phone number: ${payload.recipient}`;
+      this.logger.error(error);
+      return {
+        notificationId: payload.id,
+        channel: this.channel,
+        success: false,
+        error,
+        deliveredAt: new Date(),
+      };
+    }
+
+    // Render template
+    const body = this.renderTemplate(payload);
+
+    // Build the SMS message
+    const message: SmsMessage = {
+      to: recipient,
+      from: this.config.fromNumber,
+      body,
+    };
+
+    try {
+      const result = await this.transport.sendSms(message);
+      this.logger.info(`SMS delivered: ${result.messageId} to ${recipient}`);
+
+      this.sentMessages.push(payload);
+
+      return {
+        notificationId: payload.id,
+        channel: this.channel,
+        success: true,
+        deliveredAt: new Date(),
+      };
+    } catch (err) {
+      const error = err instanceof Error ? err.message : 'Unknown transport error';
+      this.logger.error(`SMS delivery failed for ${payload.id}: ${error}`);
+      return {
+        notificationId: payload.id,
+        channel: this.channel,
+        success: false,
+        error,
+        deliveredAt: new Date(),
+      };
+    }
+  }
+
+  /**
+   * Resolve and validate the recipient phone number.
+   * Returns the validated number or null if invalid.
+   */
+  resolveRecipient(recipient: string): string | null {
+    const trimmed = recipient.trim();
+    if (!isValidPhoneNumber(trimmed)) {
+      return null;
+    }
+    return trimmed;
+  }
+
+  /**
+   * Render the notification body using the SMS template for its type.
+   */
+  renderTemplate(payload: NotificationPayload): string {
+    const renderer = SMS_TEMPLATES[payload.type];
+    return renderer(payload, this.config.appName);
+  }
+
+  /**
+   * Get all successfully sent messages (useful for testing).
+   */
+  getSentMessages(): NotificationPayload[] {
+    return [...this.sentMessages];
+  }
+
+  /**
+   * Clear sent message history (useful for testing).
+   */
+  clearSentMessages(): void {
+    this.sentMessages = [];
+  }
+
+  /**
+   * Get the underlying transport (useful for testing with InMemorySmsTransport).
+   */
+  getTransport(): SmsTransport {
+    return this.transport;
+  }
+}

