    it('should trim whitespace', () => {
      expect(adapter.resolveRecipient('  +15551234567  ')).toBe('+15551234567');
    });

    it('should return null for invalid phone numbers', () => {
      expect(adapter.resolveRecipient('not-a-number')).toBeNull();
      expect(adapter.resolveRecipient('12345')).toBeNull();
      expect(adapter.resolveRecipient('+0123456789')).toBeNull();
      expect(adapter.resolveRecipient('')).toBeNull();
    });

    it('should accept valid E.164 phone numbers', () => {
      expect(adapter.resolveRecipient('+15551234567')).toBe('+15551234567');
      expect(adapter.resolveRecipient('+442071234567')).toBe('+442071234567');
      expect(adapter.resolveRecipient('+8613812345678')).toBe('+8613812345678');
    });
  });

