  describe('InMemorySmsTransport', () => {
    it('should generate sequential message IDs', async () => {
      const t = new InMemorySmsTransport();
      const message = { to: '+15551234567', from: '+10000000000', body: 'Test' };

      const r1 = await t.sendSms(message);
      const r2 = await t.sendSms(message);

      expect(r1.messageId).toBe('sms-0001');
      expect(r2.messageId).toBe('sms-0002');
    });

    it('should store and retrieve sent messages', async () => {
      const t = new InMemorySmsTransport();
      await t.sendSms({ to: '+15551234567', from: '+10000000000', body: 'Test' });

      expect(t.getSentMessages()).toHaveLength(1);
      expect(t.getSentMessages()[0]?.to).toBe('+15551234567');
    });

    it('should clear sent messages and reset counter', async () => {
      const t = new InMemorySmsTransport();
      await t.sendSms({ to: '+15551234567', from: '+10000000000', body: 'Test' });

      t.clear();
      expect(t.getSentMessages()).toHaveLength(0);

      const r = await t.sendSms({ to: '+15551234567', from: '+10000000000', body: 'Test' });
      expect(r.messageId).toBe('sms-0001');
    });
  });
